@pure
fn tier(score: Int) -> Text {
    if score >= 90 { ret "A"; }
    if score >= 80 { ret "B"; }
    if score >= 70 { ret "C"; }
    ret "F";
}
fn main() -> Void {
    fx {
        println(tier(95));
        println(tier(83));
        println(tier(71));
        println(tier(40));
    }
    ret;
}

@pure
fn pass(s: Int) -> Int {
    if s >= 60 { ret 1; }
    ret 0;
}
fn main() -> Void {
    let passed: Int = pass(75) + pass(50) + pass(90) + pass(40);
    let failed: Int = 4 - passed;
    fx {
        println("passed = ", passed);
        println("failed = ", failed);
    }
    ret;
}

fn fact(n: Int) -> Int {
    if n <= 1 { ret 1; }
    ret n * fact(n - 1);
}
fn main() -> Void {
    fx { println("5! = ", fact(5)); }
    ret;
}

